// ==========================================
// 输入缓存 (Draft Cache)
// ==========================================
const DRAFT_KEY_PREFIX = 'rag_draft_session_'

const saveDraft = (val) => {
  const key = DRAFT_KEY_PREFIX + route.params.sessionId
  if (val) {
    localStorage.setItem(key, val)
  } else {
    localStorage.removeItem(key)
  }
}

// Debounce helper
let draftTimer = null
const debouncedSaveDraft = (val) => {
  clearTimeout(draftTimer)
  draftTimer = setTimeout(() => {
    saveDraft(val)
  }, 300)
}

// Watch question changes and save draft with debounce
watch(question, (newVal) => {
  debouncedSaveDraft(newVal)
})

// Restore draft on session change
const restoreDraft = () => {
  const key = DRAFT_KEY_PREFIX + route.params.sessionId
  const saved = localStorage.getItem(key)
  if (saved !== null) {
    question.value = saved
  } else {
    question.value = ''
  }
}

// ==========================================
// 原生语音输入 (Voice Input)
// ==========================================
const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition
const isVoiceSupported = ref(!!SpeechRecognition)
const isRecording = ref(false)
let recognitionInstance = null

const toggleVoiceInput = () => {
  if (!isVoiceSupported.value) return
  if (isRecording.value) {
    stopVoiceInput()
  } else {
    startVoiceInput()
  }
}

const startVoiceInput = () => {
  if (!SpeechRecognition) return
  // Stop any existing instance
  if (recognitionInstance) {
    try { recognitionInstance.abort() } catch (e) {}
  }

  recognitionInstance = new SpeechRecognition()
  recognitionInstance.continuous = true
  recognitionInstance.interimResults = true
  recognitionInstance.lang = 'zh-CN'

  recognitionInstance.onresult = (event) => {
    let finalTranscript = ''
    for (let i = event.resultIndex; i < event.results.length; i++) {
      const transcript = event.results[i][0].transcript
      if (event.results[i].isFinal) {
        finalTranscript += transcript
      }
    }
    if (finalTranscript) {
      // 追加到 question，如果已有内容则加空格
      if (question.value) {
        question.value += ' ' + finalTranscript
      } else {
        question.value = finalTranscript
      }
    }
  }

  recognitionInstance.onerror = (event) => {
    console.warn('Speech recognition error:', event.error)
    isRecording.value = false
  }

  recognitionInstance.onend = () => {
    isRecording.value = false
    recognitionInstance = null
  }

  try {
    recognitionInstance.start()
    isRecording.value = true
  } catch (e) {
    console.error('Failed to start recognition:', e)
    isRecording.value = false
  }
}

const stopVoiceInput = () => {
  if (recognitionInstance) {
    try {
      recognitionInstance.stop()
    } catch (e) {}
    recognitionInstance = null
  }
  isRecording.value = false
}

